int arena_slot_alloc(Arena *a, size_t req) {
    size_t need = blk_align(req + HDR_SIZE + FTR_SIZE);
    Block *fit = find_fit(a, need);
    size_t total;
    int idx;
    if (!fit) {
        return -1;
